<!DOCTYPE html>
<html>
<head>
  <title>Snake Game</title>
  <style>
    body {
      background-color: #1e1e1e;
      display: flex;
      justify-content: center;
      align-items: center;
      height: 100vh;
      margin: 0;
    }

    #snake-game {
      display: flex;
      width: 400px;
      height: 400px;
    }

    #snake {
      position: absolute;
      border: 2px solid #fff;
    }

    .cell {
      width: 10px;
      height: 10px;
      box-sizing: border-box;
    }

    #food {
      position: absolute;
      border: 3px solid #ff0;
    }

    button {
      padding: 10px 20px;
      font-size: 16px;
      cursor: pointer;
      background-color: #333;
      color: #fff;
      border: none;
      margin: 10px;
    }

    #score {
      font-size: 24px;
      color: #fff;
      text-align: center;
    }
  </style>
</head>
<body>
  <div id="snake-game">
    <canvas id="snake"></canvas>
    <div>
      <button id="start">Start</button>
      <button id="pause">Pause</button>
      <button id="reset">Reset</button>
    </div>
    <div id="score">Score: 0</div>
  </div>

  <script>
    const w = 10;
    const h = 10;
    const boardSize = w * 20;
    const canvas = document.getElementById('snake');
    canvas.width = boardSize;
    canvas.height = boardSize;
    const ctx = canvas.getContext('2d');

    let snake = [[0, 0], [1, 0], [2, 0]];
    let food = [5, 5];
    let score = 0;
    let direction = 'right';
    let gameInterval;

    const startButton = document.getElementById('start');
    const pauseButton = document.getElementById('pause');
    const resetButton = document.getElementById('reset');

    function draw() {
      ctx.clearRect(0, 0, boardSize, boardSize);

      for (let i = 0; i < snake.length; i++) {
        const x = snake[i][0] * 20;
        const y = snake[i][1] * 20;
        ctx.fillRect(x, y, 10, 10);
      }

      ctx.fillRect(food[0] * 20, food[1] * 20, 10, 10);
    }

    function update() {
      const headX = snake[0][0] * 20;
      const headY = snake[0][1] * 20;

      if (headX < 0 || headX >= boardSize / 20 || headY < 0 || headY >= boardSize / 20) {
        return false; // Hit wall
      }

      for (let i = 1; i < snake.length; i++) {
        if (snake[i][0] === headX && snake[i][1] === headY) {
          return false; // Hit itself
        }
      }

      const newHead = [headX + direction === 'right' ? 1 : (direction === 'left' ? -1 : 0),
                      headY + direction === 'down' ? 1 : (direction === 'up' ? -1 : 0)];

      snake.unshift(newHead);

      if (newHead[0] === food[0] && newHead[1] === food[1]) {
        score += 10;
        food = [Math.floor(Math.random() * w), Math.floor(Math.random() * h)];
      } else {
        snake.pop();
      }

      return true;
    }

    function startGame() {
      gameInterval = setInterval(tick, 100);
      startButton.disabled = true;
      pauseButton.disabled = false;
      resetButton.disabled = false;
    }

    function tick() {
      if (!alive()) {
        clearInterval(gameInterval);
        startButton.disabled = false;
        pauseButton.disabled = true;
        resetButton.disabled = true;
        return;
      }
      update();
      draw();
      document.getElementById('score').innerText = 'Score: ' + score;
    }

    function setDir(dir) {
      if (direction === dir) return;
      direction = dir;
    }

    function setFood(x, y) {
      food = [x, y];
    }

    function snake() {
      return [...snake];
    }

    function food() {
      return food;
    }

    function alive() {
      return update();
    }

    function score() {
      return score;
    }

    window.game = {
      w, h,
      reset: () => {
        snake = [[0, 0], [1, 0], [2, 0]];
        food = [5, 5];
        score = 0;
        direction = 'right';
        startGame();
      },
      tick: tick,
      setDir: setDir,
      setFood: setFood,
      snake: snake,
      food: food,
      alive: alive,
      score: score,
    };

    startButton.addEventListener('click', startGame);
    pauseButton.addEventListener('click', () => clearInterval(gameInterval));
    resetButton.addEventListener('click', () => {
      window.game.reset();
    });
  </script>
</body>
</html>
